def make_aff(query):
    return f'https://www.amazon.com/s?k={query.replace(" ", "+")}&tag={AFF}'

def faq_json(topic):
    entries = FAQS[topic][:3]
    return '[\n    ' + ',\n    '.join('{ "@type": "Question", "name": "%s", "acceptedAnswer": { "@type": "Answer", "text": "%s" } }' % (q.replace('"','&quot;'), a.replace('"','&quot;')) for q,a in entries) + '\n  ]'

def render(domain, topic, filename, title, angle):
    desc = f"{title} ranked for {angle}. Compare real options, see a buying guide, and shop Amazon picks with honest pros and cons."
    if len(desc) > 158:
        desc = desc[:157].rsplit(' ',1)[0] + '.'
    prods = PRODUCTS[topic]
    cards = []
    for idx,(name,blurb,pros,cons) in enumerate(prods, start=1):
        badge = "Editor's Pick" if idx == 1 else ('Best Value' if idx == 2 else f'#{idx} Pick')
        cls = 'badge value' if idx == 2 else 'badge'
        cards.append(f'''<div class="product-card"><div class="{cls}">{badge}</div><h2>{escape(name)}</h2><p>{escape(blurb)} Built for shoppers researching {escape(angle)} rather than the whole category at once.</p><div class="pros-cons"><div class="pros"><h4>Pros</h4><ul>{''.join(f'<li>{escape(x)}</li>' for x in pros)}</ul></div><div class="cons"><h4>Cons</h4><ul>{''.join(f'<li>{escape(x)}</li>' for x in cons)}</ul></div></div><a class="btn" href="{make_aff(name)}" target="_blank" rel="nofollow noopener">Check Price on Amazon</a></div>''')
    rows = ''.join(f'<tr><td>{escape(name)}</td><td>{"Budget" if i==1 else "Mid-Range" if i in (2,3) else "Premium"}</td><td>{escape(blurb[:70])}</td></tr>' for i,(name,blurb,_,__) in enumerate(prods, start=1))
    faqs_html = ''.join(f'<div class="faq-item"><h3>{escape(q)}</h3><p>{escape(a)}</p></div>' for q,a in FAQS[topic])
    browse = ''.join(f'<li><a href="/{href}">{escape(label)}</a></li>' for label,href in LINKS[domain])
    return f'''<!DOCTYPE html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{escape(title)} | {domain}</title><meta name="description" content="{escape(desc)}"><link rel="canonical" href="https://{domain}/{filename}"><meta property="og:title" content="{escape(title)}"><meta property="og:description" content="{escape(desc)}"><meta property="og:url" content="https://{domain}/{filename}"><meta property="og:type" content="article"><meta name="twitter:card" content="summary"><script type="application/ld+json">{{"@context":"https://schema.org","@type":"FAQPage","mainEntity":{faq_json(topic)}}}</script><style>{SIMPLE_STYLE}</style></head>
<body><header><div class="logo">{domain}</div><nav><a href="/">Home</a><a href="/{SITE_CONFIGS[domain]['base']}">Main Guide</a><a href="/buyers-guide.html">Buyer's Guide</a><a href="/about.html">About</a></nav></header><div class="hero"><h1>{escape(title)}</h1><p>This page focuses on {escape(angle)}, so the recommendations favor the buyers most likely to care about that use case instead of generic one-size-fits-all advice.</p><a class="btn" href="/{SITE_CONFIGS[domain]['base']}">See Main Rankings</a></div><div class="container"><p style="color:#aaa;margin-bottom:24px">We compare real products, not imaginary winners. Every Amazon link uses affiliate tag <code>{AFF}</code>, which helps keep the site running at no extra cost to you.</p>{''.join(cards)}<table class="comparison-table"><thead><tr><th>Product</th><th>Positioning</th><th>Why It Stands Out</th></tr></thead><tbody>{rows}</tbody></table><div class="guide-box"><h2>Buying Guide</h2><p>When comparing {topic}, ignore lazy ranking pages that only repeat spec sheets. Start with your actual use case: {escape(angle)}. That one detail usually determines whether compact convenience, stronger output, or premium features matter most.</p><p>Next, look at ownership friction. The right product is the one you will keep using, cleaning, storing, and recommending six months from now. That means build quality, support reputation, and ease of use matter more than marketing claims.</p><p>Finally, buy enough quality once. The cheapest option often becomes expensive when it disappoints early, while the most expensive option is only worth it if its advantages actually show up in your real routine.</p></div><div class="browse-more"><h2>Browse More</h2><ul>{browse}</ul></div></div><div class="faq-section"><div class="container"><h2>Frequently Asked Questions</h2>{faqs_html}</div></div><footer><p>&copy; 2026 {domain} — Independent product reviews. Amazon affiliate links use tag={AFF}. <a href="/about.html">About</a> · <a href="/contact.html">Contact</a></p></footer></body></html>'''

def update_index(domain, cfg):
    path = cfg['dir'] / 'index.html'
    text = path.read_text()
    links = ''.join(f'<li><a href="/{fn}">{escape(title)}</a></li>' for fn,title,_ in cfg['pages'][:10])
    block = f'<div class="browse-more"><h2>Browse More</h2><ul>{links}</ul></div>'
    if 'Browse More' in text:
        text = re.sub(r'<div class="browse-more">.*?</div>', block, text, count=1, flags=re.S)
    elif '</footer>' in text:
        text = text.replace('</footer>', block + '</footer>')
    elif '</body>' in text:
        text = text.replace('</body>', block + '</body>')
    path.write_text(text)

def update_sitemap(domain, cfg):
    urls = [''] + [cfg['base'],'buyers-guide.html','about.html','contact.html'] + [fn for fn,_,_ in cfg['pages']]
    seen = []
    for u in urls:
        if u not in seen:
            seen.append(u)
    items = []
    for u in seen:
        loc = f'https://{domain}/' + u
        items.append(f'  <url><loc>{loc}</loc><lastmod>{TODAY}</lastmod><changefreq>weekly</changefreq></url>')
    (cfg['dir']/'sitemap.xml').write_text('<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n' + '\n'.join(items) + '\n</urlset>\n')

def main():
    report = []
    for domain,cfg in SITE_CONFIGS.items():
        created = 0
        for fn,title,angle in cfg['pages']:
            (cfg['dir']/fn).write_text(render(domain, cfg['topic'], fn, title, angle))
            created += 1
        update_index(domain, cfg)
        update_sitemap(domain, cfg)
        total = len(list(cfg['dir'].glob('*.html')))
        report.append((domain, created, total))
    for domain,created,total in report:
        print(domain, created, total)

if __name__ == '__main__':
    main()
